INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_EFECTIVO', 'Efectivo', 'Pago en efectivo en moneda local al momento de la compra o entrega.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_TARJETA_CRED', 'Tarjeta de Credito', 'Pago electronico diferido mediante franquicias como Visa, Mastercard o Amex.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_TARJETA_DEB', 'Tarjeta de Debito', 'Pago electronico con debito inmediato de la cuenta de ahorros o corriente.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_PAYPAL', 'PayPal', 'Transaccion en linea segura mediante billetera digital vinculada a correo electronico.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_TRANSFERENCIA', 'Transferencia', 'Transferencia electronica bancaria directa (SPEI, ACH o transferencias locales).');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_CRIPTOMONEDA', 'Criptomonedas', 'Pago utilizando activos digitales descentralizados como Bitcoin, Ethereum o USDT.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_APPLE_PAY', 'Apple Pay', 'Pago movil sin contacto y digital a traves de dispositivos del ecosistema Apple.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_GOOGLE_PAY', 'Google Pay', 'Plataforma de billetera digital desarrollada por Google para transacciones rapidas.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_CONTRAENTREGA', 'Contraentrega', 'El pago se realiza en el momento exacto de recibir el producto en fisico.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_VALES_DESP', 'Vales de Despensa', 'Monedero electronico corporativo destinado a la compra de canasta basica.');
INSERT INTO public.metodo_pago (id_metodo_pago, nombre_metodo, descripcion) VALUES ('MP_SIN_DESC', 'Por Determinar', 'N/A');
