--
-- Base de datos: sushi_green
-- Proyecto SGE - Sushi Green (Grupo FMC S.A.S.)
-- Curso 750006C Bases de Datos - Grupo 01 - Universidad del Valle - 2026-1
--
-- Esquema relacional normalizado (3FN) + carga completa de datos.
-- 22 tablas | 5164 registros | PostgreSQL 17
--
-- USO: abrir en pgAdmin (Query Tool) sobre una base 'sushi_green' vacia
--      y ejecutar completo (F5).
--

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET search_path = public;


-- =====================================================================
-- 1. DEFINICION DE TABLAS (DDL)
-- =====================================================================

CREATE TABLE public.cargo (

    id_cargo character varying(20) NOT NULL,
    nombre_cargo character varying(20) NOT NULL,
    labor character varying(30) NOT NULL
);

CREATE TABLE public.categoria (

    id_categoria character varying(20) NOT NULL,
    nombre_categoria character varying(50) NOT NULL,
    descripcion character varying(200) DEFAULT 'No hay información disponible'::character varying
);

CREATE TABLE public.cliente (

    cedula_cliente character varying(20) NOT NULL,
    nombre character varying(20) NOT NULL,
    apellido character varying(20) NOT NULL,
    telefono character varying(20) NOT NULL
);

CREATE TABLE public.detalle_pedido (

    id_detalle character varying(20) NOT NULL,
    id_pedido character varying(20) NOT NULL,
    id_producto character varying(20) NOT NULL,
    cantidad_producto integer NOT NULL,
    precio_unitario numeric(10,2) NOT NULL,
    subtotal numeric(10,2) NOT NULL,
    observaciones character varying(20) DEFAULT 'No hay observaciones'::character varying,
    CONSTRAINT detalle_pedido_cantidad_producto_check CHECK ((cantidad_producto > 0)),
    CONSTRAINT detalle_pedido_precio_unitario_check CHECK ((precio_unitario >= (0)::numeric)),
    CONSTRAINT detalle_pedido_subtotal_check CHECK ((subtotal >= (0)::numeric))
);

CREATE TABLE public.detalle_pedido_prov (

    id_detalle_prov character varying(20) NOT NULL,
    id_pedido_prov character varying(20) NOT NULL,
    id_ingrediente character varying(20) NOT NULL,
    cantidad_solicitada numeric(10,2) NOT NULL,
    precio_compra numeric(10,2) NOT NULL,
    CONSTRAINT detalle_pedido_prov_cantidad_solicitada_check CHECK ((cantidad_solicitada > (0)::numeric)),
    CONSTRAINT detalle_pedido_prov_precio_compra_check CHECK ((precio_compra > (0)::numeric))
);

CREATE TABLE public.empleado (

    cedula_empleado character varying(20) NOT NULL,
    id_cargo character varying(20) NOT NULL,
    id_turno character varying(20) NOT NULL,
    id_sede character varying(20) NOT NULL,
    nombre character varying(30) NOT NULL,
    apellido character varying(30) NOT NULL,
    celular character varying(20) NOT NULL,
    direccion character varying(50) NOT NULL,
    correo character varying(100) NOT NULL,
    fecha_nacimiento date NOT NULL,
    fecha_contratacion date NOT NULL,
    salario numeric(10,2) NOT NULL,
    tipo_contrato character varying(20) NOT NULL,
    eps character varying(20) DEFAULT 'No aplica'::character varying,
    arl character varying(20) NOT NULL,
    estado_empleado character varying(20) NOT NULL,
    CONSTRAINT empleado_salario_check CHECK ((salario > (0)::numeric))
);

CREATE TABLE public.factura (

    id_factura character varying(20) NOT NULL,
    cedula_cliente character varying(20),
    numero_factura character varying(20) NOT NULL,
    fecha_factura date NOT NULL,
    hora_factura time without time zone NOT NULL,
    subtotal numeric(10,2) NOT NULL,
    impuestos numeric(10,2) DEFAULT 0,
    propina numeric(10,2) DEFAULT 0,
    total numeric(10,2) NOT NULL,
    resolucion_dian character varying(20) NOT NULL,
    nit_empresa character varying(20) NOT NULL,
    CONSTRAINT factura_impuestos_check CHECK ((impuestos >= (0)::numeric)),
    CONSTRAINT factura_propina_check CHECK ((propina >= (0)::numeric)),
    CONSTRAINT factura_subtotal_check CHECK ((subtotal >= (0)::numeric)),
    CONSTRAINT factura_total_check CHECK ((total >= (0)::numeric))
);

CREATE TABLE public.ingrediente (

    id_ingrediente character varying(20) NOT NULL,
    nombre_ingrediente character varying(100) NOT NULL,
    unidad_medida character varying(20) NOT NULL,
    stock_minimo numeric(10,2) NOT NULL,
    estado_ingrediente character varying(20) DEFAULT 'No hay información'::character varying,
    CONSTRAINT ingrediente_stock_minimo_check CHECK ((stock_minimo >= (0)::numeric))
);

CREATE TABLE public.ingreso_inventario (

    id_ingreso character varying(20) NOT NULL,
    nit_proveedor character varying(20) NOT NULL,
    id_inventario character varying(20) NOT NULL,
    fecha_ingreso date NOT NULL,
    hora_ingreso time without time zone NOT NULL,
    cantidad_ingresada numeric(10,2) NOT NULL,
    numero_factura character varying(20) NOT NULL,
    CONSTRAINT ingreso_inventario_cantidad_ingresada_check CHECK ((cantidad_ingresada > (0)::numeric))
);

CREATE TABLE public.inventario (

    id_inventario character varying(20) NOT NULL,
    id_ingrediente character varying(20) NOT NULL,
    id_sede character varying(20) NOT NULL,
    cantidad_disponible numeric(10,2) NOT NULL,
    fecha_actualizacion date NOT NULL,
    CONSTRAINT inventario_cantidad_disponible_check CHECK ((cantidad_disponible >= (0)::numeric))
);

CREATE TABLE public.mesa (

    id_mesa character varying(20) NOT NULL,
    id_sede character varying(20) NOT NULL,
    numero_mesa integer,
    capacidad integer,
    CONSTRAINT mesa_capacidad_check CHECK (((capacidad >= 1) AND (capacidad <= 10))),
    CONSTRAINT mesa_numero_mesa_check CHECK (((numero_mesa >= 1) AND (numero_mesa <= 40)))
);

CREATE TABLE public.metodo_pago (

    id_metodo_pago character varying(20) NOT NULL,
    nombre_metodo character varying(20) NOT NULL,
    descripcion character varying(100) DEFAULT 'N/A'::character varying
);

CREATE TABLE public.pago (

    id_pago character varying(20) NOT NULL,
    id_factura character varying(20) NOT NULL,
    id_metodo_pago character varying(20) NOT NULL,
    valor_pago numeric(10,2) NOT NULL,
    fecha_pago timestamp without time zone NOT NULL,
    referencia_pago character varying(20) NOT NULL,
    CONSTRAINT pago_valor_pago_check CHECK ((valor_pago > (0)::numeric))
);

CREATE TABLE public.pedido (

    id_pedido character varying(20) NOT NULL,
    id_empleado character varying(20) NOT NULL,
    id_mesa character varying(20),
    id_factura character varying(20) NOT NULL,
    id_plataforma character varying(20),
    cedula_cliente character varying(20),
    fecha_pedido date NOT NULL,
    hora_pedido time without time zone NOT NULL,
    tipo_pedido character varying(20) NOT NULL,
    estado_pedido character varying(20) NOT NULL,
    subtotal numeric(10,2) NOT NULL,
    impuestos numeric(10,2) NOT NULL,
    propina numeric(10,2) NOT NULL,
    total numeric(10,2) NOT NULL,
    observaciones character varying(20) DEFAULT 'N/A'::character varying,
    CONSTRAINT pedido_impuestos_check CHECK ((impuestos >= (0)::numeric)),
    CONSTRAINT pedido_propina_check CHECK ((propina >= (0)::numeric)),
    CONSTRAINT pedido_subtotal_check CHECK ((subtotal >= (0)::numeric)),
    CONSTRAINT pedido_total_check CHECK ((total >= (0)::numeric))
);

CREATE TABLE public.pedido_proveedor (

    id_pedido_prov character varying(20) NOT NULL,
    nit_proveedor character varying(20) NOT NULL,
    fecha_pedido date NOT NULL,
    estado character varying(20) DEFAULT 'pendiente'::character varying,
    total_pedido numeric(10,2) NOT NULL,
    CONSTRAINT pedido_proveedor_total_pedido_check CHECK ((total_pedido >= (0)::numeric))
);

CREATE TABLE public.plataforma_domicilio (

    id_plataforma character varying(20) NOT NULL,
    nombre_plataforma character varying(20) NOT NULL,
    telefono_soporte character varying(20) NOT NULL,
    pagina_web character varying(20) DEFAULT NULL::character varying
);

CREATE TABLE public.producto (

    id_producto character varying(20) NOT NULL,
    id_categoria character varying(20) NOT NULL,
    nombre_producto character varying(100) NOT NULL,
    descripcion character varying(300) DEFAULT 'No hay información disponible'::character varying,
    precio numeric(10,2) NOT NULL,
    estado_producto character varying(20) DEFAULT 'No hay información'::character varying,
    CONSTRAINT producto_precio_check CHECK ((precio > (0)::numeric))
);

CREATE TABLE public.producto_ingrediente (

    id_producto character varying(20) NOT NULL,
    id_ingrediente character varying(20) NOT NULL,
    cantidad_utilizada numeric(10,2) NOT NULL,
    CONSTRAINT producto_ingrediente_cantidad_utilizada_check CHECK ((cantidad_utilizada > (0)::numeric))
);

CREATE TABLE public.proveedor (

    nit_proveedor character varying(20) NOT NULL,
    nombre_proveedor character varying(20) NOT NULL,
    telefono character varying(20) NOT NULL,
    direccion character varying(50) NOT NULL,
    correo character varying(30) NOT NULL,
    tipo_proveedor character varying(20) DEFAULT 'N/A'::character varying,
    estado_proveedor character varying(20) DEFAULT 'No hay información'::character varying
);

CREATE TABLE public.reserva (

    id_reserva character varying(20) NOT NULL,
    cedula_cliente character varying(20) NOT NULL,
    id_mesa character varying(20) NOT NULL,
    fecha_reserva date NOT NULL,
    hora_reserva time without time zone NOT NULL,
    cantidad_personas integer,
    estado_reserva character varying(20) NOT NULL,
    observaciones character varying(30) DEFAULT 'N/A'::character varying,
    CONSTRAINT reserva_cantidad_personas_check CHECK ((cantidad_personas >= 1))
);

CREATE TABLE public.sede (

    id_sede character varying(20) NOT NULL,
    nombre_sede character varying(50) NOT NULL,
    direccion character varying(100) NOT NULL,
    telefono character varying(20) NOT NULL
);

CREATE TABLE public.turno (

    id_turno character varying(20) NOT NULL,
    tipo_turno character varying(20) NOT NULL,
    hora_inicio time without time zone NOT NULL,
    hora_fin time without time zone NOT NULL,
    CONSTRAINT turno_check CHECK ((hora_fin > hora_inicio))
);


